import{_ as t,o as s,c as e,a2 as i}from"./chunks/framework.Crpw6aS5.js";const b=JSON.parse('{"title":"使用指南","description":"","frontmatter":{"title":"使用指南"},"headers":[],"relativePath":"guide/how-to-use.md","filePath":"guide/how-to-use.md","lastUpdated":null}'),n={name:"guide/how-to-use.md"};function l(r,a,d,h,p,o){return s(),e("div",null,[...a[0]||(a[0]=[i(`<h1 id="使用指南" tabindex="-1">使用指南 <a class="header-anchor" href="#使用指南" aria-label="Permalink to &quot;使用指南&quot;">​</a></h1><h2 id="知识库组织方式" tabindex="-1">知识库组织方式 <a class="header-anchor" href="#知识库组织方式" aria-label="Permalink to &quot;知识库组织方式&quot;">​</a></h2><p>本知识库按照<strong>五层学习架构</strong>组织内容，遵循从基础到进阶的认知规律：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>第一层：语言基础 → 第二层：语言深入 → 第三层：框架应用 → 第四层：分布式体系 → 第五层：综合进阶</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>每一层的知识都建立在前一层的基础之上，建议按顺序学习。</p><h2 id="知识条目结构" tabindex="-1">知识条目结构 <a class="header-anchor" href="#知识条目结构" aria-label="Permalink to &quot;知识条目结构&quot;">​</a></h2><p>每个知识条目都遵循统一的内容结构：</p><ol><li><strong>概念说明</strong> — 用通俗易懂的语言解释知识点</li><li><strong>核心原理</strong> — 深入分析底层原理，配合流程图说明</li><li><strong>代码示例</strong> — 关键代码片段 + 完整可运行代码链接</li><li><strong>常见面试题</strong> — 高频面试题、答题思路、深入追问</li></ol><h2 id="难度标识" tabindex="-1">难度标识 <a class="header-anchor" href="#难度标识" aria-label="Permalink to &quot;难度标识&quot;">​</a></h2><p>每个知识条目都标注了难度级别和面试频率：</p><table tabindex="0"><thead><tr><th>难度</th><th>说明</th><th>适合人群</th></tr></thead><tbody><tr><td>初级 (beginner)</td><td>基础概念和用法</td><td>校招 / 初级岗位</td></tr><tr><td>中级 (intermediate)</td><td>原理和源码分析</td><td>中级岗位 / 大厂初面</td></tr><tr><td>高级 (advanced)</td><td>底层实现和架构设计</td><td>高级岗位 / 大厂深面</td></tr></tbody></table><table tabindex="0"><thead><tr><th>面试频率</th><th>说明</th></tr></thead><tbody><tr><td>🔥🔥🔥 高频</td><td>几乎每次面试都会问，必须掌握</td></tr><tr><td>🔥🔥 中频</td><td>经常出现，应该掌握</td></tr><tr><td>🔥 低频</td><td>偶尔出现，了解即可</td></tr></tbody></table><h2 id="代码示例使用" tabindex="-1">代码示例使用 <a class="header-anchor" href="#代码示例使用" aria-label="Permalink to &quot;代码示例使用&quot;">​</a></h2><p>文档中的代码示例分为两种：</p><ol><li><strong>内嵌代码片段</strong> — 直接在文档中展示关键代码</li><li><strong>完整可运行代码</strong> — 链接到 <code>code-examples/</code> 中的 Maven 子模块</li></ol><p>运行完整代码示例：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> code-examples</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 编译特定子模块</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mvn</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> compile</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -pl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> java-basics</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 运行测试</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mvn</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -pl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> java-basics</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 运行 main 方法</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mvn</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> exec:java</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -pl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> java-basics</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -Dexec.mainClass=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;com.example.basics.YourDemo&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><h2 id="搜索功能" tabindex="-1">搜索功能 <a class="header-anchor" href="#搜索功能" aria-label="Permalink to &quot;搜索功能&quot;">​</a></h2><p>点击页面顶部的搜索框（或按 <code>Ctrl+K</code> / <code>Cmd+K</code>），输入关键词即可全文搜索。</p><p>搜索范围覆盖：</p><ul><li>知识条目标题</li><li>正文内容</li><li>代码注释</li></ul><h2 id="学习路径推荐" tabindex="-1">学习路径推荐 <a class="header-anchor" href="#学习路径推荐" aria-label="Permalink to &quot;学习路径推荐&quot;">​</a></h2><p>根据你的水平和目标，选择合适的学习路径：</p><table tabindex="0"><thead><tr><th>路径</th><th>适合人群</th><th>预计时长</th></tr></thead><tbody><tr><td><a href="/learning-paths/beginner.html">Java 初学者</a></td><td>刚接触 Java 的开发者</td><td>4-6 周</td></tr><tr><td><a href="/learning-paths/intermediate.html">Java 中级进阶</a></td><td>有 1-2 年经验的开发者</td><td>6-8 周</td></tr><tr><td><a href="/learning-paths/advanced.html">Java 高级深入</a></td><td>有 3 年以上经验的开发者</td><td>8-12 周</td></tr><tr><td><a href="/learning-paths/interview-sprint.html">面试突击</a></td><td>准备面试的开发者</td><td>2-4 周</td></tr><tr><td><a href="/learning-paths/architect.html">架构师成长</a></td><td>向架构师方向发展的开发者</td><td>12-16 周</td></tr></tbody></table><h2 id="面试准备" tabindex="-1">面试准备 <a class="header-anchor" href="#面试准备" aria-label="Permalink to &quot;面试准备&quot;">​</a></h2><p>每个知识模块都包含面试指南（<code>interview.md</code>），汇总了该领域的高频面试题。</p><p>此外，还提供：</p><ul><li><a href="/interview/by-company.html">按公司类型分类的面试重点</a></li><li><a href="/interview/knowledge-map.html">面试知识图谱</a></li></ul>`,28)])])}const k=t(n,[["render",l]]);export{b as __pageData,k as default};
